```javascript
(function() {
  'use strict';

  if (document.getElementById('__okki_intercept_panel')) {
    document.getElementById('__okki_intercept_panel').remove();
  }

  const panel = document.createElement('div');
  panel.id = '__okki_intercept_panel';
  panel.innerHTML = '<div style="position:fixed; bottom:20px; right:20px; z-index:999999; background:#1a1a2e; color:#e0e0e0; border-radius:12px; padding:16px; font:12px/1.5 Consolas,Monaco,monospace; box-shadow:0 8px 32px rgba(0,0,0,0.5); width:420px; border:1px solid #333;"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;"><span style="font-size:14px;font-weight:700;color:#4fc3f7;">OKKI API Monitor v2</span><span id="__okki_status" style="font-size:11px;color:#66bb6a;">● 监听中</span></div><div id="__okki_counter" style="margin-bottom:8px;font-size:11px;color:#999;">已捕获: 0 个请求</div><div id="__okki_list" style="max-height:300px;overflow-y:auto;margin-bottom:10px;font-size:10px;color:#aaa;word-break:break-all;"><div style="color:#555;">等待请求...</div></div><div style="display:flex;gap:8px;"><button id="__okki_export" style="flex:1;padding:8px;background:#4fc3f7;color:#000;border:none;border-radius:6px;cursor:pointer;font-weight:700;font-size:12px;">导出JSON</button><button id="__okki_clear" style="flex:1;padding:8px;background:#333;color:#ccc;border:none;border-radius:6px;cursor:pointer;font-size:12px;">清空</button><button id="__okki_close" style="padding:8px 12px;background:#444;color:#999;border:none;border-radius:6px;cursor:pointer;font-size:12px;">X</button></div></div>';
  document.body.appendChild(panel);

  const captured = [];
  const seen = new Set();

  function updateUI(method, url, status, info) {
    const list = document.getElementById('__okki_list');
    if (list.querySelector('div[style]')) list.innerHTML = '';
    const el = document.createElement('div');
    el.style.cssText = 'padding:3px 0;border-bottom:1px solid #222;';
    let label = status >= 400 ? 'color:#ef5350;' : 'color:#66bb6a;';
    el.innerHTML = '<span style="' + label + '">' + method + ' ' + status + '</span> ' + url + (info ? ' <span style="color:#ffab40;">' + info + '</span>' : '');
    list.insertBefore(el, list.firstChild);
    while (list.children.length > 50) list.removeChild(list.lastChild);
    document.getElementById('__okki_counter').innerHTML = '已捕获: ' + captured.length + ' 个请求';
  }

  // Capture ALL xiaoman.cn fetch calls, no URL path filter
  const origFetch = window.fetch;
  window.fetch = function(...args) {
    const url = typeof args[0] === 'string' ? args[0] : args[0]?.url || '';
    return origFetch.apply(this, args).then(async (res) => {
      if (!seen.has(url) && url.includes('xiaoman.cn') && !url.includes('.jpg') && !url.includes('.png') && !url.includes('.avif') && !url.includes('.js') && !url.includes('.css')) {
        seen.add(url);
        const cloned = res.clone();
        let info = '';
        try {
          const ct = cloned.headers.get('content-type') || '';
          if (ct.includes('json')) {
            const body = await cloned.json();
            const arr = Array.isArray(body);
            const n = arr ? body.length : (body?.data && Array.isArray(body.data) ? body.data.length : (body?.result && Array.isArray(body.result) ? body.result.length : null));
            info = n ? '[' + n + '条]' : (body ? 'keys:' + Object.keys(body).slice(0, 8).join(',') : '');
            captured.push({ method: args[1]?.method || 'GET', url, status: res.status, recordCount: n, bodyKeys: typeof body==='object' && !arr ? Object.keys(body).slice(0, 15) : null, sample: JSON.stringify(body).substring(0, 300) });
          } else {
            info = 'type:' + ct.substring(0, 30);
            captured.push({ method: args[1]?.method || 'GET', url, status: res.status, type: ct });
          }
        } catch(e) { info = 'parse err'; captured.push({ method: args[1]?.method || 'GET', url, status: res.status }); }
        updateUI(args[1]?.method || 'GET', url.substring(0, 100), res.status, info);
      }
      return res;
    });
  };

  // Also capture XHR
  const O = XMLHttpRequest.prototype.open, S = XMLHttpRequest.prototype.send;
  XMLHttpRequest.prototype.open = function(m, u, ...r) { this.__u = u; this.__m = m; return O.apply(this, [m, u, ...r]); };
  XMLHttpRequest.prototype.send = function(...a) {
    const x = this, url = x.__u || '';
    x.addEventListener('load', function() {
      if (!seen.has(url) && url.includes('xiaoman.cn') && !url.includes('.jpg') && !url.includes('.png') && !url.includes('.js') && !url.includes('.css')) {
        seen.add(url);
        let info = '';
        try {
          const ct = x.getResponseHeader('content-type') || '';
          if (ct.includes('json')) {
            const body = JSON.parse(x.responseText);
            const arr = Array.isArray(body);
            const n = arr ? body.length : (body?.data && Array.isArray(body.data) ? body.data.length : (body?.result && Array.isArray(body.result) ? body.result.length : null));
            info = n ? '[' + n + '条]' : 'keys:' + Object.keys(body||{}).slice(0,8).join(',');
            captured.push({ method: x.__m || 'GET', url, status: x.status, recordCount: n, bodyKeys: typeof body==='object' && !arr ? Object.keys(body).slice(0,15) : null, sample: JSON.stringify(body).substring(0, 300) });
          } else {
            info = 'type:' + ct;
            captured.push({ method: x.__m || 'GET', url, status: x.status });
          }
        } catch(e) { info = 'parse err'; captured.push({ method: x.__m || 'GET', url, status: x.status }); }
        updateUI(x.__m || 'GET', url.substring(0, 100), x.status, info);
      }
    });
    return S.apply(this, a);
  };

