  document.body.appendChild(panel);

  const captured = [];
  let counter = 0;

  function add(url) {
    if (captured.find(c => c.url === url)) return;
    counter++;
    captured.push({ url });
    const l = document.getElementById('__l');
    if (l.querySelector('div[style]')) l.innerHTML = '';
    const el = document.createElement('div');
    el.style.cssText = 'padding:3px 0;border-bottom:1px solid #222;';
    el.textContent = url.substring(0, 120);
    l.insertBefore(el, l.firstChild);
    while (l.children.length > 50) l.removeChild(l.lastChild);
    document.getElementById('__c').innerHTML = '已捕获: ' + counter + ' 个请求';
  }

  // Method 1: PerformanceObserver - captures ALL network entries
  try {
    const po = new PerformanceObserver((list) => {
      for (const entry of list.getEntries()) {
        if (entry.name && entry.name.includes('xiaoman.cn') && !/\.(jpg|png|avif|gif|svg|js|css|woff|ttf|ico)/i.test(entry.name)) {
          add(entry.name);
        }
      }
    });
    po.observe({ type: 'resource', buffered: true });
  } catch(e) { console.log('PO err:', e.message); }

  // Method 2: fetch + XHR intercept as backup
  const of = window.fetch;
  window.fetch = function(...a) {
    const u = typeof a[0] === 'string' ? a[0] : a[0]?.url || '';
    if (u.includes('xiaoman.cn') && !/\.(jpg|png|avif|gif|svg|js|css|woff|ttf|ico)/i.test(u)) add(u);
    return of.apply(this, a);
  };
  const O = XMLHttpRequest.prototype.open, S = XMLHttpRequest.prototype.send;
  XMLHttpRequest.prototype.open = function(m,u,...r) { this.__u=u; return O.apply(this,[m,u,...r]); };
  XMLHttpRequest.prototype.send = function(...a) {
    const x=this; if(x.__u && x.__u.includes('xiaoman.cn') && !/\.(jpg|png|avif|gif|svg|js|css|woff)/i.test(x.__u)) add(x.__u);
    return S.apply(this,a);
  };

  document.getElementById('__e').onclick = function() {
    const ts = new Date().toISOString().replace(/[:.]/g, '-');
    const blob = new Blob([JSON.stringify({ exportedAt: new Date().toISOString(), total: captured.length, urls: captured }, null, 2)], { type: 'application/json' });
    const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'okki_urls_' + ts + '.json'; a.click();
    document.getElementById('__s').innerHTML = '<span style="color:#ffab40;">已导出 ' + captured.length + ' 条</span>';
  };
  document.getElementById('__x').onclick = function() { captured.length = 0; counter = 0; document.getElementById('__l').innerHTML = '<div style="color:#555;">已清空 — 现在去刷新页面或切换页面</div>'; document.getElementById('__c').innerHTML = '已捕获: 0'; };
  document.getElementById('__z').onclick = function() { document.getElementById('__okki_intercept_panel').remove(); };

  console.log('%cOKKI Monitor v3 已激活 %c| 右下角 | 支持 PerformanceObserver+fetch+XHR', 'color:#4fc3f7;font-weight:bold;', 'color:#999;');
})();
